+//! Virtual File System Reader Abstraction
+//!
+//! Type-erased reader interface that enables model loading from multiple sources:
+//! - Local files (FileReader)
+//! - Memory buffers (MemoryReader)
+//! - HTTP Range requests (HttpReader) - for cloud-hosted models
+//!
+//! Pattern adapted from lanceql's io/reader.zig implementation.
+
+const std = @import("std");
+const Allocator = std.mem.Allocator;
+
+const log = std.log.scoped(.vfs_reader);
+
+pub const ReadError = error{
+    EndOfStream,
+    InvalidOffset,
+    ReadFailed,
+    HttpError,
+    NetworkError,
+    OpenFailed,
+    OutOfMemory,
+};
+
+/// Type-erased reader interface via vtable pattern
+/// Enables zero-cost abstraction over different data sources
+pub const Reader = struct {
+    ptr: *anyopaque,
+    vtable: *const VTable,
+
+    pub const VTable = struct {
+        /// Read bytes at offset into buffer, returns bytes read
+        read: *const fn (ptr: *anyopaque, offset: u64, buffer: []u8) ReadError!usize,
+        /// Get total size in bytes
+        size: *const fn (ptr: *anyopaque) ReadError!u64,
+        /// Cleanup resources
+        deinit: *const fn (ptr: *anyopaque) void,
+    };
+
+    /// Read bytes at offset
+    pub fn read(self: Reader, offset: u64, buffer: []u8) ReadError!usize {
+        return self.vtable.read(self.ptr, offset, buffer);
+    }
+
+    /// Read all bytes at offset (blocks until complete)
+    pub fn readAll(self: Reader, offset: u64, buffer: []u8) ReadError!void {
+        var total_read: usize = 0;
+        while (total_read < buffer.len) {
+            const n = try self.read(offset + total_read, buffer[total_read..]);
+            if (n == 0) return ReadError.EndOfStream;
+            total_read += n;
+        }
+    }
+
+    /// Get total size
+    pub fn getSize(self: Reader) ReadError!u64 {
+        return self.vtable.size(self.ptr);
+    }
+
+    /// Cleanup
+    pub fn deinit(self: Reader) void {
+        self.vtable.deinit(self.ptr);
+    }
+};
+
+// =============================================================================
+// FileReader - Local filesystem
+// =============================================================================
+
+pub const FileReader = struct {
+    allocator: Allocator,
+    file: std.fs.File,
+    file_size: u64,
+
+    const Self = @This();
+
+    pub fn init(allocator: Allocator, path: []const u8) !Self {
+        const file = std.fs.cwd().openFile(path, .{}) catch |err| {
+            log.err("Failed to open file: {s}", .{path});
+            return switch (err) {
+                error.FileNotFound => ReadError.OpenFailed,
+                else => ReadError.OpenFailed,
+            };
+        };
+
+        const stat = try file.stat();
+
+        return Self{
+            .allocator = allocator,
+            .file = file,
+            .file_size = stat.size,
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.file.close();
+    }
+
+    fn readFn(ptr: *anyopaque, offset: u64, buffer: []u8) ReadError!usize {
+        const self: *Self = @ptrCast(@alignCast(ptr));
+
+        self.file.seekTo(offset) catch return ReadError.InvalidOffset;
+        return self.file.read(buffer) catch ReadError.ReadFailed;
+    }
+
+    fn sizeFn(ptr: *anyopaque) ReadError!u64 {
+        const self: *Self = @ptrCast(@alignCast(ptr));
+        return self.file_size;
+    }
+
+    fn deinitFn(ptr: *anyopaque) void {
+        const self: *Self = @ptrCast(@alignCast(ptr));
+        self.deinit();
+    }
+
+    const vtable = Reader.VTable{
+        .read = readFn,
+        .size = sizeFn,
+        .deinit = deinitFn,
+    };
+
+    pub fn reader(self: *Self) Reader {
+        return .{
+            .ptr = self,
+            .vtable = &vtable,
+        };
+    }
+};
+
+// =============================================================================
+// MemoryReader - In-memory buffer
+// =============================================================================
+
+pub const MemoryReader = struct {
+    data: []const u8,
+    owns_data: bool,
+    allocator: ?Allocator,
+
+    const Self = @This();
+
+    /// Create from borrowed slice (caller owns memory)
+    pub fn initBorrowed(data: []const u8) Self {
+        return Self{
+            .data = data,
+            .owns_data = false,
+            .allocator = null,
+        };
+    }
+
+    /// Create from owned slice (will be freed on deinit)
+    pub fn initOwned(allocator: Allocator, data: []const u8) Self {
+        return Self{
+            .data = data,
+            .owns_data = true,
+            .allocator = allocator,
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        if (self.owns_data) {
+            if (self.allocator) |alloc| {
+                alloc.free(self.data);
+            }
+        }
+    }
+
+    fn readFn(ptr: *anyopaque, offset: u64, buffer: []u8) ReadError!usize {
+        const self: *Self = @ptrCast(@alignCast(ptr));
+
+        if (offset >= self.data.len) return 0;
+
+        const start: usize = @intCast(offset);
+        const available = self.data.len - start;
+        const to_read = @min(available, buffer.len);
+
+        @memcpy(buffer[0..to_read], self.data[start..][0..to_read]);
+        return to_read;
+    }
+
+    fn sizeFn(ptr: *anyopaque) ReadError!u64 {
+        const self: *Self = @ptrCast(@alignCast(ptr));
+        return self.data.len;
+    }
+
+    fn deinitFn(ptr: *anyopaque) void {
+        const self: *Self = @ptrCast(@alignCast(ptr));
+        self.deinit();
+    }
+
+    const vtable = Reader.VTable{
+        .read = readFn,
+        .size = sizeFn,
+        .deinit = deinitFn,
+    };
+
+    pub fn reader(self: *Self) Reader {
+        return .{
+            .ptr = self,
+            .vtable = &vtable,
+        };
+    }
+};
+
+// =============================================================================
+// HttpReader - HTTP Range requests (for cloud-hosted models)
+// =============================================================================
+
+pub const HttpReader = struct {
+    allocator: Allocator,
+    uri: std.Uri,
+    content_length: u64,
+    uri_str: []const u8,
+
+    const Self = @This();
+
+    /// Initialize HTTP reader, performs HEAD request to get content length
+    pub fn init(allocator: Allocator, url: []const u8) !Self {
+        const uri = std.Uri.parse(url) catch return ReadError.NetworkError;
+
+        // Perform HEAD request to get content length
+        var client = std.http.Client{ .allocator = allocator };
+        defer client.deinit();
+
+        var header_buf: [4096]u8 = undefined;
+        var req = client.open(.HEAD, uri, .{
+            .server_header_buffer = &header_buf,
+        }) catch return ReadError.NetworkError;
+        defer req.deinit();
+
+        req.send() catch return ReadError.NetworkError;
+        req.wait() catch return ReadError.NetworkError;
+
+        const status = req.response.status;
+        if (status != .ok and status != .no_content) {
+            log.err("HTTP HEAD failed: {}", .{status});
+            return ReadError.HttpError;
+        }
+
+        const content_length = req.response.content_length orelse {
+            log.err("Server did not return Content-Length");
+            return ReadError.HttpError;
+        };
+
+        return Self{
+            .allocator = allocator,
+            .uri = uri,
+            .content_length = content_length,
+            .uri_str = try allocator.dupe(u8, url),
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.allocator.free(self.uri_str);
+    }
+
+    fn readFn(ptr: *anyopaque, offset: u64, buffer: []u8) ReadError!usize {
+        const self: *Self = @ptrCast(@alignCast(ptr));
+
+        if (offset >= self.content_length) return 0;
+
+        // Fresh client per request (avoids connection pooling issues)
+        var client = std.http.Client{ .allocator = self.allocator };
+        defer client.deinit();
+
+        // Build Range header
+        var range_buf: [64]u8 = undefined;
+        const end = @min(offset + buffer.len - 1, self.content_length - 1);
+        const range_str = std.fmt.bufPrint(&range_buf, "bytes={d}-{d}", .{ offset, end }) catch
+            return ReadError.InvalidOffset;
+
+        var header_buf: [4096]u8 = undefined;
+        var req = client.open(.GET, self.uri, .{
+            .server_header_buffer = &header_buf,
+            .extra_headers = &.{
+                .{ .name = "Range", .value = range_str },
+            },
+        }) catch return ReadError.NetworkError;
+        defer req.deinit();
+
+        req.send() catch return ReadError.NetworkError;
+        req.wait() catch return ReadError.NetworkError;
+
+        // Accept both 200 (full) and 206 (partial content)
+        const status = req.response.status;
+        if (status != .ok and status != .partial_content) {
+            log.err("HTTP GET failed: {}", .{status});
+            return ReadError.HttpError;
+        }
+
+        // Read response body
+        const n = req.reader().read(buffer) catch return ReadError.ReadFailed;
+        return n;
+    }
+
+    fn sizeFn(ptr: *anyopaque) ReadError!u64 {
+        const self: *Self = @ptrCast(@alignCast(ptr));
+        return self.content_length;
+    }
+
+    fn deinitFn(ptr: *anyopaque) void {
+        const self: *Self = @ptrCast(@alignCast(ptr));
+        self.deinit();
+    }
+
+    const vtable = Reader.VTable{
+        .read = readFn,
+        .size = sizeFn,
+        .deinit = deinitFn,
+    };
+
+    pub fn reader(self: *Self) Reader {
+        return .{
+            .ptr = self,
+            .vtable = &vtable,
+        };
+    }
+};
+
+// =============================================================================
+// Helper: Auto-detect reader type from path/URL
+// =============================================================================
+
+pub const ReaderType = enum {
+    file,
+    memory,
+    http,
+    https,
+};
+
+/// Detect reader type from path string
+pub fn detectReaderType(path: []const u8) ReaderType {
+    if (std.mem.startsWith(u8, path, "http://")) return .http;
+    if (std.mem.startsWith(u8, path, "https://")) return .https;
+    return .file;
+}
+
+// =============================================================================
+// Tests
+// =============================================================================
+
+test "memory reader" {
+    const data = "Hello, World!";
+    var reader_impl = MemoryReader.initBorrowed(data);
+    defer reader_impl.deinit();
+
+    const r = reader_impl.reader();
+
+    // Test size
+    const size = try r.getSize();
+    try std.testing.expectEqual(@as(u64, 13), size);
+
+    // Test read at offset 0
+    var buf: [5]u8 = undefined;
+    const n = try r.read(0, &buf);
+    try std.testing.expectEqual(@as(usize, 5), n);
+    try std.testing.expectEqualStrings("Hello", &buf);
+
+    // Test read at offset 7
+    const n2 = try r.read(7, &buf);
+    try std.testing.expectEqual(@as(usize, 5), n2);
+    try std.testing.expectEqualStrings("World", &buf);
+}
+
+test "file reader" {
+    const allocator = std.testing.allocator;
+
+    // Create test file
+    const test_path = "/tmp/vfs_reader_test.bin";
+    {
+        const file = try std.fs.cwd().createFile(test_path, .{});
+        defer file.close();
+        try file.writeAll("Test file content 12345");
+    }
+    defer std.fs.cwd().deleteFile(test_path) catch {};
+
+    var reader_impl = try FileReader.init(allocator, test_path);
+    defer reader_impl.deinit();
+
+    const r = reader_impl.reader();
+
+    // Test size
+    const size = try r.getSize();
+    try std.testing.expectEqual(@as(u64, 23), size);
+
+    // Test read
+    var buf: [4]u8 = undefined;
+    const n = try r.read(0, &buf);
+    try std.testing.expectEqual(@as(usize, 4), n);
+    try std.testing.expectEqualStrings("Test", &buf);
+}
+
+test "detect reader type" {
+    try std.testing.expectEqual(ReaderType.http, detectReaderType("http://example.com/model.gguf"));
+    try std.testing.expectEqual(ReaderType.https, detectReaderType("https://huggingface.co/model.gguf"));
+    try std.testing.expectEqual(ReaderType.file, detectReaderType("/path/to/model.gguf"));
+    try std.testing.expectEqual(ReaderType.file, detectReaderType("./models/model.gguf"));
+}

