+//! Request-Scoped Bump Allocator
+//!
+//! Fast arena-style allocator for request/batch processing where all allocations
+//! can be freed at once between requests. No per-allocation bookkeeping overhead.
+//!
+//! Pattern adapted from lanceql's wasm.zig bump allocator.
+//!
+//! Usage:
+//!   var req_alloc = RequestAllocator.init(backing_allocator, 1 * 1024 * 1024);
+//!   defer req_alloc.deinit();
+//!
+//!   // Process request
+//!   const tokens = try req_alloc.allocator().alloc(u32, 1024);
+//!   // ... use tokens ...
+//!
+//!   // Reset for next request (O(1), no per-allocation free)
+//!   req_alloc.reset();
+
+const std = @import("std");
+const Allocator = std.mem.Allocator;
+
+const log = std.log.scoped(.request_allocator);
+
+/// Request-scoped bump allocator with O(1) reset
+pub const RequestAllocator = struct {
+    /// Backing memory (allocated from parent allocator)
+    buffer: []align(16) u8,
+    /// Current allocation offset
+    offset: usize,
+    /// High water mark for diagnostics
+    peak_usage: usize,
+    /// Request counter for diagnostics
+    request_count: usize,
+    /// Parent allocator (for buffer management)
+    parent: Allocator,
+
+    const Self = @This();
+
+    /// Initialize with fixed-size buffer
+    pub fn init(parent: Allocator, size: usize) !Self {
+        const buffer = try parent.alignedAlloc(u8, 16, size);
+        return Self{
+            .buffer = buffer,
+            .offset = 0,
+            .peak_usage = 0,
+            .request_count = 0,
+            .parent = parent,
+        };
+    }
+
+    /// Initialize with static buffer (no parent allocator needed)
+    pub fn initStatic(buffer: []align(16) u8) Self {
+        return Self{
+            .buffer = buffer,
+            .offset = 0,
+            .peak_usage = 0,
+            .request_count = 0,
+            .parent = undefined,
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        // Only free if we have a valid parent allocator
+        if (@intFromPtr(&self.parent.vtable) != 0) {
+            self.parent.free(self.buffer);
+        }
+    }
+
+    /// Reset allocator for next request (O(1) operation)
+    pub fn reset(self: *Self) void {
+        // Track peak usage
+        self.peak_usage = @max(self.peak_usage, self.offset);
+        self.request_count += 1;
+
+        // Clear offset - all previous allocations invalidated
+        self.offset = 0;
+    }
+
+    /// Get remaining capacity
+    pub fn remaining(self: *const Self) usize {
+        return self.buffer.len - self.offset;
+    }
+
+    /// Get current usage
+    pub fn usage(self: *const Self) usize {
+        return self.offset;
+    }
+
+    /// Get peak usage across all requests
+    pub fn peakUsage(self: *const Self) usize {
+        return @max(self.peak_usage, self.offset);
+    }
+
+    /// Get utilization percentage
+    pub fn utilizationPercent(self: *const Self) f32 {
+        if (self.buffer.len == 0) return 0;
+        return @as(f32, @floatFromInt(self.peakUsage())) / @as(f32, @floatFromInt(self.buffer.len)) * 100.0;
+    }
+
+    /// Get statistics
+    pub fn getStats(self: *const Self) Stats {
+        return .{
+            .buffer_size = self.buffer.len,
+            .current_usage = self.offset,
+            .peak_usage = self.peakUsage(),
+            .request_count = self.request_count,
+            .utilization = self.utilizationPercent(),
+        };
+    }
+
+    pub const Stats = struct {
+        buffer_size: usize,
+        current_usage: usize,
+        peak_usage: usize,
+        request_count: usize,
+        utilization: f32,
+    };
+
+    /// Allocator interface
+    pub fn allocator(self: *Self) Allocator {
+        return .{
+            .ptr = self,
+            .vtable = &.{
+                .alloc = alloc,
+                .resize = resize,
+                .free = free,
+            },
+        };
+    }
+
+    fn alloc(ctx: *anyopaque, len: usize, ptr_align: u8, _: usize) ?[*]u8 {
+        const self: *Self = @ptrCast(@alignCast(ctx));
+        return self.allocInner(len, ptr_align);
+    }
+
+    fn allocInner(self: *Self, len: usize, ptr_align: u8) ?[*]u8 {
+        // Align offset
+        const alignment: usize = @as(usize, 1) << @intCast(ptr_align);
+        const aligned_offset = std.mem.alignForward(usize, self.offset, alignment);
+        const padding = aligned_offset - self.offset;
+
+        // Check capacity
+        const total_needed = padding + len;
+        if (aligned_offset + len > self.buffer.len) {
+            log.warn("Request allocator out of space: need {}, have {}", .{
+                total_needed,
+                self.remaining(),
+            });
+            return null;
+        }
+
+        // Bump offset
+        self.offset = aligned_offset + len;
+
+        return @ptrCast(&self.buffer[aligned_offset]);
+    }
+
+    fn resize(_: *anyopaque, _: []u8, _: u8, _: usize, _: usize) bool {
+        // Bump allocator doesn't support resize
+        return false;
+    }
+
+    fn free(_: *anyopaque, _: []u8, _: u8, _: usize) void {
+        // No-op: bump allocator frees everything on reset()
+    }
+};
+
+/// Thread-local request allocator for concurrent request handling
+pub const ThreadLocalRequestAllocator = struct {
+    /// Per-thread allocators
+    allocators: []RequestAllocator,
+    /// Number of threads
+    thread_count: usize,
+    /// Parent allocator
+    parent: Allocator,
+
+    const Self = @This();
+
+    pub fn init(parent: Allocator, thread_count: usize, per_thread_size: usize) !Self {
+        const allocators = try parent.alloc(RequestAllocator, thread_count);
+        errdefer parent.free(allocators);
+
+        for (allocators, 0..) |*alloc, i| {
+            alloc.* = RequestAllocator.init(parent, per_thread_size) catch |err| {
+                // Cleanup already initialized allocators
+                for (allocators[0..i]) |*a| a.deinit();
+                return err;
+            };
+        }
+
+        return Self{
+            .allocators = allocators,
+            .thread_count = thread_count,
+            .parent = parent,
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        for (self.allocators) |*alloc| {
+            alloc.deinit();
+        }
+        self.parent.free(self.allocators);
+    }
+
+    /// Get allocator for current thread
+    pub fn get(self: *Self) *RequestAllocator {
+        const thread_id = std.Thread.getCurrentId();
+        const idx = thread_id % self.thread_count;
+        return &self.allocators[idx];
+    }
+
+    /// Reset all thread allocators
+    pub fn resetAll(self: *Self) void {
+        for (self.allocators) |*alloc| {
+            alloc.reset();
+        }
+    }
+
+    /// Get aggregate statistics
+    pub fn getStats(self: *Self) AggregateStats {
+        var total_usage: usize = 0;
+        var total_peak: usize = 0;
+        var total_capacity: usize = 0;
+        var total_requests: usize = 0;
+
+        for (self.allocators) |*alloc| {
+            const stats = alloc.getStats();
+            total_usage += stats.current_usage;
+            total_peak += stats.peak_usage;
+            total_capacity += stats.buffer_size;
+            total_requests += stats.request_count;
+        }
+
+        return .{
+            .thread_count = self.thread_count,
+            .total_capacity = total_capacity,
+            .total_usage = total_usage,
+            .total_peak = total_peak,
+            .total_requests = total_requests,
+        };
+    }
+
+    pub const AggregateStats = struct {
+        thread_count: usize,
+        total_capacity: usize,
+        total_usage: usize,
+        total_peak: usize,
+        total_requests: usize,
+    };
+};
+
+// =============================================================================
+// Tests
+// =============================================================================
+
+test "request allocator basic" {
+    const parent = std.testing.allocator;
+
+    var req_alloc = try RequestAllocator.init(parent, 4096);
+    defer req_alloc.deinit();
+
+    const alloc = req_alloc.allocator();
+
+    // Allocate some memory
+    const buf1 = try alloc.alloc(u8, 100);
+    try std.testing.expectEqual(@as(usize, 100), buf1.len);
+
+    const buf2 = try alloc.alloc(u32, 50);
+    try std.testing.expectEqual(@as(usize, 50), buf2.len);
+
+    // Check usage
+    try std.testing.expect(req_alloc.usage() >= 100 + 50 * 4);
+
+    // Reset
+    req_alloc.reset();
+    try std.testing.expectEqual(@as(usize, 0), req_alloc.usage());
+    try std.testing.expectEqual(@as(usize, 1), req_alloc.request_count);
+}
+
+test "request allocator alignment" {
+    const parent = std.testing.allocator;
+
+    var req_alloc = try RequestAllocator.init(parent, 4096);
+    defer req_alloc.deinit();
+
+    const alloc = req_alloc.allocator();
+
+    // Allocate with different alignments
+    _ = try alloc.alloc(u8, 1);
+    const aligned = try alloc.alignedAlloc(u64, 64, 10);
+
+    // Check alignment
+    const addr = @intFromPtr(aligned.ptr);
+    try std.testing.expectEqual(@as(usize, 0), addr % 64);
+}
+
+test "request allocator exhaustion" {
+    const parent = std.testing.allocator;
+
+    var req_alloc = try RequestAllocator.init(parent, 256);
+    defer req_alloc.deinit();
+
+    const alloc = req_alloc.allocator();
+
+    // Allocate until exhausted
+    _ = try alloc.alloc(u8, 200);
+
+    // This should fail (not enough space)
+    const result = alloc.alloc(u8, 100);
+    try std.testing.expectEqual(@as(?[]u8, null), result);
+}
+
+test "request allocator stats" {
+    const parent = std.testing.allocator;
+
+    var req_alloc = try RequestAllocator.init(parent, 4096);
+    defer req_alloc.deinit();
+
+    const alloc = req_alloc.allocator();
+
+    // First request
+    _ = try alloc.alloc(u8, 1000);
+    req_alloc.reset();
+
+    // Second request (larger)
+    _ = try alloc.alloc(u8, 2000);
+    req_alloc.reset();
+
+    // Third request (smaller)
+    _ = try alloc.alloc(u8, 500);
